import { useCallback, useEffect, useRef, useState } from 'react';

export interface UseUnsavedChangesGuardResult {
  showUnsavedModal: boolean;
  setShowUnsavedModal: (open: boolean) => void;
  guardedAction: (fn: () => void) => void;
  confirmLeave: () => void;
  cancelLeave: () => void;
}

/**
 * Blocks navigation/actions when the form has unsaved edits.
 */
export function useUnsavedChangesGuard(
  isDirty: boolean,
  enabled = true,
): UseUnsavedChangesGuardResult {
  const [showUnsavedModal, setShowUnsavedModal] = useState(false);
  const pendingActionRef = useRef<(() => void) | null>(null);
  const active = enabled && isDirty;

  useEffect(() => {
    const handler = (e: BeforeUnloadEvent) => {
      if (!active) return;
      e.preventDefault();
      e.returnValue = '';
    };
    window.addEventListener('beforeunload', handler);
    return () => window.removeEventListener('beforeunload', handler);
  }, [active]);

  const guardedAction = useCallback(
    (fn: () => void) => {
      if (!active) {
        fn();
        return;
      }
      pendingActionRef.current = fn;
      setShowUnsavedModal(true);
    },
    [active],
  );

  const confirmLeave = useCallback(() => {
    setShowUnsavedModal(false);
    pendingActionRef.current?.();
    pendingActionRef.current = null;
  }, []);

  const cancelLeave = useCallback(() => {
    setShowUnsavedModal(false);
    pendingActionRef.current = null;
  }, []);

  return {
    showUnsavedModal,
    setShowUnsavedModal,
    guardedAction,
    confirmLeave,
    cancelLeave,
  };
}
